-- Catalog: add subject "PP221: Fundamentals of Public Policy" (LU-01..03), placed on TOP.
-- Newest subject goes first (prepended); existing subjects keep their order below it.
-- This APPENDS one subject; it does not rewrite existing subjects/readings, so prior link
-- fixes stay intact. Idempotent (re-running won't duplicate). Reading IDs are pp221-prefixed
-- so completions never collide with PP231's lu01m01-style IDs.
-- Paste the statement below into the Supabase SQL Editor and Run.
update public.catalog c
set data = jsonb_set(
  c.data,
  '{subjects}',
  (
    select jsonb_agg(q.s order by q.ord)
    from (
      select $pp${"id":"pp221","lus":[{"id":"pp221_lu01","url":"https://opentakshashila.net/posts/pgp10-lu-01-nation-states-and-governments","title":"LU-01: Nation, States and Governments","outcomes":["Understand the fundamental concepts in politics — distinguishing nations, states and governments, and use these terms precisely","Explore the ideas of the Indian nation","Explore theories of the origin and purpose of the state","Understand India's system of government","Compare and contrast the concepts of nation, state and government in India to that of other countries"],"mandatory":[{"id":"pp221_lu01_m01","url":"https://repository.law.umich.edu/cgi/viewcontent.cgi?article=1285&context=mjil","desc":"Stephen D. Krasner deliberates on sovereignty and the idea of shared sovereignty (2004)","name":"The Hole in the Whole"},{"id":"pp221_lu01_m02","url":"https://www.nitinpai.in/2008/09/04/on-liberal-nationalism/","desc":"Essay by Nitin Pai connecting Liberalism, Nationalism and Realism","name":"On Liberal Nationalism"},{"id":"pp221_lu01_m03","url":"https://aud.delhi.gov.in/sites/default/files/2024-01/slgr-readings/partha_chatterjee_state_compressed.pdf","desc":"Partha Chatterjee gives a historical perspective of the Indian state, its structure and evolution (Oxford Companion to Politics in India, Ch. 1)","name":"The State"},{"id":"pp221_lu01_m04","url":"https://media2-production.mightynetworks.com/asset/2b2208fd-f905-4462-991f-610c3b5e74ae/PP221-_Imagined_Communites_-_Benedict_Anderson.pdf","desc":"Book by Benedict Anderson","name":"Imagined Communities"}],"selfStudy":false,"recommended":[{"id":"pp221_lu01_r01","url":"https://media2-production.mightynetworks.com/asset/f305b0bc-c0a5-4dfa-851a-ccb0add98795/803881.pdf","desc":"State and Government in Ancient India — Chapter 2, pages 26–41","name":"Origin and Type of State"},{"id":"pp221_lu01_r02","url":"https://www.business-standard.com/article/opinion/nitin-pai-the-flash-mobs-of-class-warfare-111121900036_1.html","desc":"Nitin Pai (note: the article argues this is not a classical class struggle)","name":"The flash mobs of class warfare"},{"id":"pp221_lu01_r03","url":"https://www.pewresearch.org/global/wp-content/uploads/sites/2/2017/02/Pew-Research-Center-National-Identity-Report-FINAL-February-1-2017.pdf","desc":"Pew Research Centre report on national identity","name":"What It Takes to Truly Be 'One of Us'"}]},{"id":"pp221_lu02","url":"https://opentakshashila.net/posts/pgp10-lu-02-democracy-republic-and-constitution","title":"LU-02: Democracy, Republic, and Constitution","outcomes":["Appreciate the fundamental limitations of government as an agent","Understand the concepts of principal-agent problem, asymmetric information, moral hazard, the time factor and scaling, and how they lead to unintended consequences","Understand how, in India, the Republic's social mission, contested information, time dynamics, scaling and the governance gap impose additional limitations on the government"],"mandatory":[{"id":"pp221_lu02_m01","url":"https://media2-production.mightynetworks.com/asset/edfc98b4-9c7b-4b58-8186-46f7c93f6f1e/The_grammar_of_anarchy.pdf","desc":"Essay in Pragati on the need for Constitutional Anarchy","name":"The grammar of anarchy"},{"id":"pp221_lu02_m02","url":"https://media2-production.mightynetworks.com/asset/ad9dbc40-c665-4ced-862f-414217c41e2b/Why_is_India_a_Flailing_State.pdf","desc":"Blogpost by The Gentle Leviathan, a newsletter on policy, politics and development in India","name":"Why is India a Flailing State?"},{"id":"pp221_lu02_m03","url":"https://media2-production.mightynetworks.com/asset/a5ab5973-a393-4dfc-b72c-449f9b4c6b2f/Kapur__2020__-_Why_does_the_Indian_State_both_Fail_and_Succeed.pdf","desc":"Paper by Devesh Kapur (Journal of Economic Perspectives, 2020) on why the Indian state is good at some things and not others","name":"Why does the Indian state both fail and succeed?"},{"id":"pp221_lu02_m04","url":"https://youtu.be/nKsh2GMgdbE","desc":"Video","name":"How India became a democratic nation? (video)"},{"id":"pp221_lu02_m05","url":"https://media2-production.mightynetworks.com/asset/69aded52-c19b-498b-bc78-45ba347293a4/The_policymaker_as_a_tightrope_walker.pdf","desc":"Common pitfalls a policymaker runs into","name":"The policymaker as a tight rope walker"},{"id":"pp221_lu02_m06","url":"https://media2-production.mightynetworks.com/asset/9c5876e6-154d-49f2-bb10-c343377febb9/Pritchett__2009__-_Is_India_a_Flailing_State.pdf","desc":"Lant Pritchett (HKS, 2009) on why the Indian state can formulate excellent policies but falls short on execution","name":"Is India a Flailing State?"}],"selfStudy":false,"recommended":[]},{"id":"pp221_lu03","url":"https://opentakshashila.net/posts/pgp10-lu-03-structure-and-goals-of-public-policy","title":"LU-03: Structure and Goals of Public Policy","outcomes":["Understand what the field of public policy and public policy analysis covers","Establish important caveats and limitations that affect policy analysis","Frame content and themes for the introduction to public policy analysis course"],"mandatory":[{"id":"pp221_lu03_m01","url":"https://media2-production.mightynetworks.com/asset/69aded52-c19b-498b-bc78-45ba347293a4/The_policymaker_as_a_tightrope_walker.pdf","desc":"Common pitfalls a policymaker runs into","name":"Policymaker as a tightrope walker"},{"id":"pp221_lu03_m02","url":"https://media2-production.mightynetworks.com/asset/ce80f61f-33fc-4ae0-855d-1a2e3c304100/Demonetization_and_Policy_Credibility.pdf","desc":"How demonetisation fared against its stated objectives","name":"Demonetization and Policy Credibility"},{"id":"pp221_lu03_m03","url":"https://media2-production.mightynetworks.com/asset/594b2328-244e-4fe5-b6a7-cd6c40ddd0df/Goals_of_Public_Policy.pdf","desc":"Deborah Stone details the goals of public policy and why a government and the market are fundamentally different","name":"Goals of Public Policy"},{"id":"pp221_lu03_m04","url":"https://media2-production.mightynetworks.com/asset/c059bc9b-4eb6-453c-ab79-c721f72ceb89/In_Service_of_the_Republic_-_Ch._2__11__28.pdf","desc":"Ch. 2, 11, 28 — reasons for policy failure and a primer on choosing among interventions","name":"In Service of the Republic — Ch. 2, 11, 28"},{"id":"pp221_lu03_m05","url":"https://media2-production.mightynetworks.com/asset/f4724908-b923-455b-9833-50fcfabae604/PAISA_for_Municipalities.pdf","desc":"How the structure and functions of a government play out at the local level","name":"Paisa for Municipalities"}],"selfStudy":false,"recommended":[{"id":"pp221_lu03_r01","url":"https://media2-production.mightynetworks.com/asset/1f24f37c-a381-49da-8c41-defe728bf239/In_service_of_the_republic___Kelkar___Shah_Ch._29.pdf","desc":"Kelkar & Shah, Chapter 29","name":"In service of the republic — Kelkar & Shah, Ch. 29"},{"id":"pp221_lu03_r02","url":"https://media2-production.mightynetworks.com/asset/55b68600-c9f4-4f8f-a843-dc0b9884807b/India_s_Failed_Demonetization_Program_and_Its_Retreating_Economic_Defenders.pdf","desc":"How demonetisation fared against its stated objectives","name":"India's Failed Demonetization Program and Its Retreating Economic Defenders"},{"id":"pp221_lu03_r03","url":"https://blog.theleapjournal.org/2018/12/concerns-with-delhi-metro.html","desc":"Shubho Roy and Ajay Shah evaluate the Delhi metro on ridership, costs and revenues","name":"Concerns with Delhi Metro"}]}],"code":"Public Policy · Fundamentals","icon":"🏛️","name":"PP221: Fundamentals of Public Policy","color":"#33406b"}$pp$::jsonb as s, 0::numeric as ord
      union all
      select s, ord::numeric + 1
        from jsonb_array_elements(c.data->'subjects') with ordinality as t(s, ord)
    ) q
  )
) || jsonb_build_object('updatedAt', 1782449868584)
where c.id = 1
  and not exists (
    select 1 from jsonb_array_elements(c.data->'subjects') e where e->>'id' = 'pp221'
  );
